  "Subfolder inside the root content folder.": "\u041F\u043E\u0434\u043F\u0430\u043F\u043A\u0430 \u0432\u043D\u0443\u0442\u0440\u0438 \u043A\u043E\u0440\u043D\u0435\u0432\u043E\u0439 \u043F\u0430\u043F\u043A\u0438 \u043A\u043E\u043D\u0442\u0435\u043D\u0442\u0430.",
  "Subject": "\u041F\u0440\u0435\u0434\u043C\u0435\u0442",
  "Subtask description...": "\u041E\u043F\u0438\u0441\u0430\u043D\u0438\u0435 \u043F\u043E\u0434\u0437\u0430\u0434\u0430\u0447\u0438...",
