  "What needs to be finished today": "\u0422\u043E, \u0447\u0442\u043E \u0432\u0430\u0436\u043D\u043E \u0437\u0430\u0432\u0435\u0440\u0448\u0438\u0442\u044C \u0432 \u0442\u0435\u0447\u0435\u043D\u0438\u0435 \u0434\u043D\u044F",
  "What should be considered?": "\u0427\u0442\u043E \u0441\u0442\u043E\u0438\u0442 \u0443\u0447\u0435\u0441\u0442\u044C?",
