  "Plugin command": "\u041A\u043E\u043C\u0430\u043D\u0434\u0430 \u043F\u043B\u0430\u0433\u0438\u043D\u0430",
  "Command example": "\u041F\u0440\u0438\u043C\u0435\u0440 \u043A\u043E\u043C\u0430\u043D\u0434\u044B",
  "Command runner": "\u0417\u0430\u043F\u0443\u0441\u043A \u043A\u043E\u043C\u0430\u043D\u0434\u044B",
  "Run command": "\u0412\u044B\u043F\u043E\u043B\u043D\u0438\u0442\u044C \u043A\u043E\u043C\u0430\u043D\u0434\u0443",
  "Autocomplete": "\u0410\u0432\u0442\u043E\u0434\u043E\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u0435",
  "autocomplete": "\u0430\u0432\u0442\u043E\u0434\u043E\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u0435",
  "example": "\u043F\u0440\u0438\u043C\u0435\u0440",
  "Task command": "\u041A\u043E\u043C\u0430\u043D\u0434\u0430 \u0437\u0430\u0434\u0430\u0447\u0438",
  "Countdown command": "\u041A\u043E\u043C\u0430\u043D\u0434\u0430 countdown",
  "Schedule command": "\u041A\u043E\u043C\u0430\u043D\u0434\u0430 \u0440\u0430\u0441\u043F\u0438\u0441\u0430\u043D\u0438\u044F",
  "Review command": "\u041A\u043E\u043C\u0430\u043D\u0434\u0430 \u0440\u0435\u0432\u044C\u044E",
  "Create a markdown task in the current note or daily note.": "\u0421\u043E\u0437\u0434\u0430\u0451\u0442 markdown-\u0437\u0430\u0434\u0430\u0447\u0443 \u0432 \u0442\u0435\u043A\u0443\u0449\u0435\u0439 \u0438\u043B\u0438 \u0435\u0436\u0435\u0434\u043D\u0435\u0432\u043D\u043E\u0439 \u0437\u0430\u043C\u0435\u0442\u043A\u0435.",
  "Add a countdown block to the current or daily note.": "\u0414\u043E\u0431\u0430\u0432\u043B\u044F\u0435\u0442 countdown-\u0431\u043B\u043E\u043A \u0432 \u0442\u0435\u043A\u0443\u0449\u0443\u044E \u0438\u043B\u0438 \u0435\u0436\u0435\u0434\u043D\u0435\u0432\u043D\u0443\u044E \u0437\u0430\u043C\u0435\u0442\u043A\u0443.",
  "Update a schedule slot.": "\u041E\u0431\u043D\u043E\u0432\u043B\u044F\u0435\u0442 \u0441\u043B\u043E\u0442 \u0440\u0430\u0441\u043F\u0438\u0441\u0430\u043D\u0438\u044F.",
  "Save a daily or weekly review field.": "\u0421\u043E\u0445\u0440\u0430\u043D\u044F\u0435\u0442 \u043F\u043E\u043B\u0435 \u0435\u0436\u0435\u0434\u043D\u0435\u0432\u043D\u043E\u0433\u043E \u0438\u043B\u0438 \u043D\u0435\u0434\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u0440\u0435\u0432\u044C\u044E.",
  "Usage: > task Description today|tomorrow|YYYY-MM-DD #tag !high": "\u0424\u043E\u0440\u043C\u0430\u0442: > task \u041E\u043F\u0438\u0441\u0430\u043D\u0438\u0435 today|tomorrow|YYYY-MM-DD #tag !high",
  "Usage: > countdown Title YYYY-MM-DD [HH:mm] accent:#27ae60 view:focus target:current": "\u0424\u043E\u0440\u043C\u0430\u0442: > countdown \u041D\u0430\u0437\u0432\u0430\u043D\u0438\u0435 YYYY-MM-DD [HH:mm] accent:#27ae60 view:focus target:current",
  "Usage: > schedule Subject monday 09:00-10:30 room:301 type:lecture week:current": "\u0424\u043E\u0440\u043C\u0430\u0442: > schedule \u041F\u0440\u0435\u0434\u043C\u0435\u0442 monday 09:00-10:30 room:301 type:lecture week:current",
  "Usage: > review win|lesson|tomorrow|weekly_win|weekly_friction|weekly_next Text": "\u0424\u043E\u0440\u043C\u0430\u0442: > review win|lesson|tomorrow|weekly_win|weekly_friction|weekly_next \u0422\u0435\u043A\u0441\u0442",
  "Complete command name": "\u0414\u043E\u043F\u043E\u043B\u043D\u0438 \u043D\u0430\u0437\u0432\u0430\u043D\u0438\u0435 \u043A\u043E\u043C\u0430\u043D\u0434\u044B",
  "Type a command after >": "\u0412\u0432\u0435\u0434\u0438 \u043A\u043E\u043C\u0430\u043D\u0434\u0443 \u043F\u043E\u0441\u043B\u0435 >",
