  "Due tomorrow": "\u0421\u0440\u043E\u043A \u0437\u0430\u0432\u0442\u0440\u0430",
  "High priority": "\u0412\u044B\u0441\u043E\u043A\u0438\u0439 \u043F\u0440\u0438\u043E\u0440\u0438\u0442\u0435\u0442",
  "Medium priority": "\u0421\u0440\u0435\u0434\u043D\u0438\u0439 \u043F\u0440\u0438\u043E\u0440\u0438\u0442\u0435\u0442",
  "Low priority": "\u041D\u0438\u0437\u043A\u0438\u0439 \u043F\u0440\u0438\u043E\u0440\u0438\u0442\u0435\u0442",
  "Accent color": "\u0410\u043A\u0446\u0435\u043D\u0442\u043D\u044B\u0439 \u0446\u0432\u0435\u0442",
  "Focus view": "\u0424\u043E\u043A\u0443\u0441\u043D\u044B\u0439 \u0432\u0438\u0434",
  "Full view": "\u041F\u043E\u043B\u043D\u044B\u0439 \u0432\u0438\u0434",
  "Minimal view": "\u041C\u0438\u043D\u0438\u043C\u0430\u043B\u044C\u043D\u044B\u0439 \u0432\u0438\u0434",
  "Write into current note": "\u0417\u0430\u043F\u0438\u0441\u0430\u0442\u044C \u0432 \u0442\u0435\u043A\u0443\u0449\u0443\u044E \u0437\u0430\u043C\u0435\u0442\u043A\u0443",
  "Write into daily note": "\u0417\u0430\u043F\u0438\u0441\u0430\u0442\u044C \u0432 daily note",
  "Existing tag": "\u0421\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0439 \u0442\u0435\u0433",
  "Room": "\u0410\u0443\u0434\u0438\u0442\u043E\u0440\u0438\u044F",
