  "Execute this command from Better Search.": "\u0412\u044B\u043F\u043E\u043B\u043D\u0438\u0442\u044C \u044D\u0442\u0443 \u043A\u043E\u043C\u0430\u043D\u0434\u0443 \u0438\u0437 \u0443\u043C\u043D\u043E\u0433\u043E \u043F\u043E\u0438\u0441\u043A\u0430.",
  "Insert this example into the search bar.": "\u0412\u0441\u0442\u0430\u0432\u0438\u0442\u044C \u044D\u0442\u043E\u0442 \u043F\u0440\u0438\u043C\u0435\u0440 \u0432 \u0441\u0442\u0440\u043E\u043A\u0443 \u043F\u043E\u0438\u0441\u043A\u0430.",
  "Recent command": "\u041D\u0435\u0434\u0430\u0432\u043D\u044F\u044F \u043A\u043E\u043C\u0430\u043D\u0434\u0430",
  "Text match": "\u0421\u043E\u0432\u043F\u0430\u0434\u0435\u043D\u0438\u0435 \u0432 \u0442\u0435\u043A\u0441\u0442\u0435",
  "Command failed": "\u041A\u043E\u043C\u0430\u043D\u0434\u0430 \u043D\u0435 \u0432\u044B\u043F\u043E\u043B\u043D\u0435\u043D\u0430",
  "Command input moved to Better Search.": "\u041A\u043E\u043C\u0430\u043D\u0434\u043D\u044B\u0439 \u0432\u0432\u043E\u0434 \u043F\u0435\u0440\u0435\u0435\u0445\u0430\u043B \u0432 \u0423\u043C\u043D\u044B\u0439 \u043F\u043E\u0438\u0441\u043A.",
  "Command copied": "\u041A\u043E\u043C\u0430\u043D\u0434\u0430 \u0441\u043A\u043E\u043F\u0438\u0440\u043E\u0432\u0430\u043D\u0430",
  "Markdown task": "Markdown-\u0437\u0430\u0434\u0430\u0447\u0430",
  "Vault image": "\u041A\u0430\u0440\u0442\u0438\u043D\u043A\u0430 \u0432 \u0445\u0440\u0430\u043D\u0438\u043B\u0438\u0449\u0435",
  "Content item": "\u042D\u043B\u0435\u043C\u0435\u043D\u0442 \u043A\u043E\u043D\u0442\u0435\u043D\u0442\u0430",
