  "presets": "\u043F\u0440\u0435\u0441\u0435\u0442\u0430",
  "Focus Session": "\u0424\u043E\u043A\u0443\u0441-\u0441\u0435\u0441\u0441\u0438\u044F",
  "A calm timer for one deliberate block of work.": "\u0421\u043F\u043E\u043A\u043E\u0439\u043D\u044B\u0439 \u0442\u0430\u0439\u043C\u0435\u0440 \u0434\u043B\u044F \u043E\u0434\u043D\u043E\u0433\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E\u0433\u043E \u0431\u043B\u043E\u043A\u0430 \u0440\u0430\u0431\u043E\u0442\u044B.",
  "Loading active tasks...": "\u0417\u0430\u0433\u0440\u0443\u0437\u043A\u0430 \u0430\u043A\u0442\u0438\u0432\u043D\u044B\u0445 \u0437\u0430\u0434\u0430\u0447...",
  "Choose a task, set the length, and start.": "\u0412\u044B\u0431\u0435\u0440\u0438 \u0437\u0430\u0434\u0430\u0447\u0443, \u0437\u0430\u0434\u0430\u0439 \u0434\u043B\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0438 \u043D\u0430\u0447\u0438\u043D\u0430\u0439.",
  "Linked task": "\u0421\u0432\u044F\u0437\u0430\u043D\u043D\u0430\u044F \u0437\u0430\u0434\u0430\u0447\u0430",
  "Manual focus": "\u0420\u0443\u0447\u043D\u043E\u0439 \u0444\u043E\u043A\u0443\u0441",
  "Focus title": "\u041D\u0430\u0437\u0432\u0430\u043D\u0438\u0435 \u0444\u043E\u043A\u0443\u0441\u0430",
