  "Mark linked task as in progress": "\u041F\u0435\u0440\u0435\u0432\u0435\u0441\u0442\u0438 \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u0443\u044E \u0437\u0430\u0434\u0430\u0447\u0443 \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441",
  "Start focus": "\u041D\u0430\u0447\u0430\u0442\u044C \u0444\u043E\u043A\u0443\u0441",
  "Focus title is required.": "\u041D\u0443\u0436\u043D\u043E \u043D\u0430\u0437\u0432\u0430\u043D\u0438\u0435 \u0444\u043E\u043A\u0443\u0441\u0430.",
  "Focus session started": "\u0424\u043E\u043A\u0443\u0441-\u0441\u0435\u0441\u0441\u0438\u044F \u043D\u0430\u0447\u0430\u043B\u0430\u0441\u044C",
  "No active tasks found. You can still start a manual focus session.": "\u0410\u043A\u0442\u0438\u0432\u043D\u044B\u0445 \u0437\u0430\u0434\u0430\u0447 \u043D\u0435 \u043D\u0430\u0439\u0434\u0435\u043D\u043E. \u041C\u043E\u0436\u043D\u043E \u0437\u0430\u043F\u0443\u0441\u0442\u0438\u0442\u044C \u0440\u0443\u0447\u043D\u0443\u044E \u0444\u043E\u043A\u0443\u0441-\u0441\u0435\u0441\u0441\u0438\u044E.",
  "Paused and waiting.": "\u041F\u0430\u0443\u0437\u0430, \u0441\u0435\u0441\u0441\u0438\u044F \u0436\u0434\u0451\u0442.",
  "Stay with one thing.": "\u0414\u0435\u0440\u0436\u0438\u043C\u0441\u044F \u043E\u0434\u043D\u043E\u0439 \u0432\u0435\u0449\u0438.",
  "Remaining": "\u041E\u0441\u0442\u0430\u043B\u043E\u0441\u044C",
  "Overtime": "\u0421\u0432\u0435\u0440\u0445 \u043F\u043B\u0430\u043D\u0430",
  "Elapsed": "\u041F\u0440\u043E\u0448\u043B\u043E",
  "Started": "\u041D\u0430\u0447\u0430\u0442\u043E",
  "Resume": "\u041F\u0440\u043E\u0434\u043E\u043B\u0436\u0438\u0442\u044C",
  "Pause": "\u041F\u0430\u0443\u0437\u0430",
  "Finish session": "\u0417\u0430\u0432\u0435\u0440\u0448\u0438\u0442\u044C \u0441\u0435\u0441\u0441\u0438\u044E",
  "Cancel session": "\u041E\u0442\u043C\u0435\u043D\u0438\u0442\u044C \u0441\u0435\u0441\u0441\u0438\u044E",
