  "Recent focus sessions": "\u041D\u0435\u0434\u0430\u0432\u043D\u0438\u0435 \u0444\u043E\u043A\u0443\u0441-\u0441\u0435\u0441\u0441\u0438\u0438",
  "No focus sessions yet.": "\u0424\u043E\u043A\u0443\u0441-\u0441\u0435\u0441\u0441\u0438\u0439 \u043F\u043E\u043A\u0430 \u043D\u0435\u0442.",
  "Progress Table": "\u0422\u0430\u0431\u043B\u0438\u0446\u0430 \u043F\u0440\u043E\u0433\u0440\u0435\u0441\u0441\u0430",
  "Universal checklist table for any grouped work.": "\u0423\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u0430\u044F \u0442\u0430\u0431\u043B\u0438\u0446\u0430 \u043E\u0442\u043C\u0435\u0442\u043E\u043A \u0434\u043B\u044F \u043B\u044E\u0431\u043E\u0439 \u0433\u0440\u0443\u043F\u043F\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0439 \u0440\u0430\u0431\u043E\u0442\u044B.",
  "Storage ID for saved cell marks.": "ID \u0434\u043B\u044F \u0441\u043E\u0445\u0440\u0430\u043D\u0435\u043D\u0438\u044F \u043E\u0442\u043C\u0435\u0442\u043E\u043A \u044F\u0447\u0435\u0435\u043A.",
  "Title above the table.": "\u0417\u0430\u0433\u043E\u043B\u043E\u0432\u043E\u043A \u043D\u0430\u0434 \u0442\u0430\u0431\u043B\u0438\u0446\u0435\u0439.",
  "Comma-separated table columns.": "\u041A\u043E\u043B\u043E\u043D\u043A\u0438 \u0442\u0430\u0431\u043B\u0438\u0446\u044B \u0447\u0435\u0440\u0435\u0437 \u0437\u0430\u043F\u044F\u0442\u0443\u044E.",
  "Groups separated by semicolons: Group: item1, item2; Other: \u21161-\u21165.": "\u0413\u0440\u0443\u043F\u043F\u044B \u0447\u0435\u0440\u0435\u0437 \u0442\u043E\u0447\u043A\u0443 \u0441 \u0437\u0430\u043F\u044F\u0442\u043E\u0439: \u0413\u0440\u0443\u043F\u043F\u0430: \u043F\u0443\u043D\u043A\u04421, \u043F\u0443\u043D\u043A\u04422; \u0414\u0440\u0443\u0433\u0430\u044F: \u21161-\u21165.",
  "Symbol shown in checked cells.": "\u0421\u0438\u043C\u0432\u043E\u043B \u0432 \u043E\u0442\u043C\u0435\u0447\u0435\u043D\u043D\u044B\u0445 \u044F\u0447\u0435\u0439\u043A\u0430\u0445.",
  "Show marked count, progress, and row count.": "\u041F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0442\u044C \u0447\u0438\u0441\u043B\u043E \u043E\u0442\u043C\u0435\u0442\u043E\u043A, \u043F\u0440\u043E\u0433\u0440\u0435\u0441\u0441 \u0438 \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u0441\u0442\u0440\u043E\u043A.",
  "General Progress": "\u041E\u0431\u0449\u0438\u0439 \u043F\u0440\u043E\u0433\u0440\u0435\u0441\u0441",
