  "Marked": "\u041E\u0442\u043C\u0435\u0447\u0435\u043D\u043E",
  "Rows": "\u0421\u0442\u0440\u043E\u043A\u0438",
  "Item": "\u041F\u0443\u043D\u043A\u0442",
  "Items": "\u041F\u0443\u043D\u043A\u0442\u044B",
  "Edit table": "\u0420\u0435\u0434\u0430\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0442\u0430\u0431\u043B\u0438\u0446\u0443",
  "Edit progress table": "\u0420\u0435\u0434\u0430\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0442\u0430\u0431\u043B\u0438\u0446\u0443 \u043F\u0440\u043E\u0433\u0440\u0435\u0441\u0441\u0430",
  "Edit columns, groups, and rows. Cell marks are kept when IDs stay the same.": "\u0420\u0435\u0434\u0430\u043A\u0442\u0438\u0440\u0443\u0439 \u043A\u043E\u043B\u043E\u043D\u043A\u0438, \u0433\u0440\u0443\u043F\u043F\u044B \u0438 \u0441\u0442\u0440\u043E\u043A\u0438. \u041E\u0442\u043C\u0435\u0442\u043A\u0438 \u0441\u043E\u0445\u0440\u0430\u043D\u044F\u044E\u0442\u0441\u044F, \u043F\u043E\u043A\u0430 id \u043E\u0441\u0442\u0430\u044E\u0442\u0441\u044F \u0442\u0435\u043C\u0438 \u0436\u0435.",
