  "Columns": "\u041A\u043E\u043B\u043E\u043D\u043A\u0438",
  "Add column": "\u0414\u043E\u0431\u0430\u0432\u0438\u0442\u044C \u043A\u043E\u043B\u043E\u043D\u043A\u0443",
  "Column name": "\u041D\u0430\u0437\u0432\u0430\u043D\u0438\u0435 \u043A\u043E\u043B\u043E\u043D\u043A\u0438",
  "Move up": "\u0412\u044B\u0448\u0435",
  "Move down": "\u041D\u0438\u0436\u0435",
  "Delete": "\u0423\u0434\u0430\u043B\u0438\u0442\u044C",
  "Groups": "\u0413\u0440\u0443\u043F\u043F\u044B",
