  "Add row": "\u0414\u043E\u0431\u0430\u0432\u0438\u0442\u044C \u0441\u0442\u0440\u043E\u043A\u0443",
  "Delete group": "\u0423\u0434\u0430\u043B\u0438\u0442\u044C \u0433\u0440\u0443\u043F\u043F\u0443",
  "New column": "\u041D\u043E\u0432\u0430\u044F \u043A\u043E\u043B\u043E\u043D\u043A\u0430",
  "New group": "\u041D\u043E\u0432\u0430\u044F \u0433\u0440\u0443\u043F\u043F\u0430",
  "New item": "\u041D\u043E\u0432\u044B\u0439 \u043F\u0443\u043D\u043A\u0442",
  "Save table": "\u0421\u043E\u0445\u0440\u0430\u043D\u0438\u0442\u044C \u0442\u0430\u0431\u043B\u0438\u0446\u0443",
  "Saving...": "\u0421\u043E\u0445\u0440\u0430\u043D\u0435\u043D\u0438\u0435...",
  "At least one column is required.": "\u041D\u0443\u0436\u043D\u0430 \u0445\u043E\u0442\u044F \u0431\u044B \u043E\u0434\u043D\u0430 \u043A\u043E\u043B\u043E\u043D\u043A\u0430.",
