  "Small amber badge": "\u041C\u0430\u043B\u0435\u043D\u044C\u043A\u0438\u0439 \u044F\u043D\u0442\u0430\u0440\u043D\u044B\u0439 \u0431\u0435\u0439\u0434\u0436",
  "Badge \u2014 Danger": "\u0411\u0435\u0439\u0434\u0436 \u2014 \u043E\u043F\u0430\u0441\u043D\u043E\u0441\u0442\u044C",
  "Small red badge": "\u041C\u0430\u043B\u0435\u043D\u044C\u043A\u0438\u0439 \u043A\u0440\u0430\u0441\u043D\u044B\u0439 \u0431\u0435\u0439\u0434\u0436",
