  "Quiet secondary text": "\u0422\u0438\u0445\u0438\u0439 \u0432\u0442\u043E\u0440\u0438\u0447\u043D\u044B\u0439 \u0442\u0435\u043A\u0441\u0442",
  "Accent Underline": "\u0410\u043A\u0446\u0435\u043D\u0442\u043D\u043E\u0435 \u043F\u043E\u0434\u0447\u0451\u0440\u043A\u0438\u0432\u0430\u043D\u0438\u0435",
  "Clean accent underline": "\u0427\u0438\u0441\u0442\u043E\u0435 \u0430\u043A\u0446\u0435\u043D\u0442\u043D\u043E\u0435 \u043F\u043E\u0434\u0447\u0451\u0440\u043A\u0438\u0432\u0430\u043D\u0438\u0435",
  "Wavy Underline": "\u0412\u043E\u043B\u043D\u0438\u0441\u0442\u043E\u0435 \u043F\u043E\u0434\u0447\u0451\u0440\u043A\u0438\u0432\u0430\u043D\u0438\u0435",
  "Questionable or needs review": "\u0421\u043E\u043C\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0438\u043B\u0438 \u043D\u0443\u0436\u043D\u043E \u043F\u0440\u043E\u0432\u0435\u0440\u0438\u0442\u044C",
  "Double Underline": "\u0414\u0432\u043E\u0439\u043D\u043E\u0435 \u043F\u043E\u0434\u0447\u0451\u0440\u043A\u0438\u0432\u0430\u043D\u0438\u0435",
