  "Paste the code from Dropbox": "\u0412\u0441\u0442\u0430\u0432\u044C \u043A\u043E\u0434 \u0438\u0437 Dropbox",
  "Dropbox OAuth": "Dropbox OAuth",
  "Generate an authorization link, open it, then paste the code here to store a local refresh token.": "\u0421\u043E\u0437\u0434\u0430\u0439 \u0441\u0441\u044B\u043B\u043A\u0443 \u0430\u0432\u0442\u043E\u0440\u0438\u0437\u0430\u0446\u0438\u0438, \u043E\u0442\u043A\u0440\u043E\u0439 \u0435\u0451, \u0437\u0430\u0442\u0435\u043C \u0432\u0441\u0442\u0430\u0432\u044C \u043A\u043E\u0434 \u0441\u044E\u0434\u0430, \u0447\u0442\u043E\u0431\u044B \u0441\u043E\u0445\u0440\u0430\u043D\u0438\u0442\u044C \u043B\u043E\u043A\u0430\u043B\u044C\u043D\u044B\u0439 refresh token.",
  "Generate auth link": "\u0421\u043E\u0437\u0434\u0430\u0442\u044C \u0441\u0441\u044B\u043B\u043A\u0443 \u0430\u0432\u0442\u043E\u0440\u0438\u0437\u0430\u0446\u0438\u0438",
  "Exchange code": "\u041E\u0431\u043C\u0435\u043D\u044F\u0442\u044C \u043A\u043E\u0434",
  "Clear Dropbox auth": "\u0421\u0431\u0440\u043E\u0441\u0438\u0442\u044C \u0430\u0432\u0442\u043E\u0440\u0438\u0437\u0430\u0446\u0438\u044E Dropbox",
  "Dropbox auth link copied": "\u0421\u0441\u044B\u043B\u043A\u0430 \u0430\u0432\u0442\u043E\u0440\u0438\u0437\u0430\u0446\u0438\u0438 Dropbox \u0441\u043A\u043E\u043F\u0438\u0440\u043E\u0432\u0430\u043D\u0430",
  "Dropbox authorization saved": "\u0410\u0432\u0442\u043E\u0440\u0438\u0437\u0430\u0446\u0438\u044F Dropbox \u0441\u043E\u0445\u0440\u0430\u043D\u0435\u043D\u0430",
  "Dropbox auth cleared": "\u0410\u0432\u0442\u043E\u0440\u0438\u0437\u0430\u0446\u0438\u044F Dropbox \u043E\u0447\u0438\u0449\u0435\u043D\u0430",
  "Dropbox app key is required": "\u041D\u0443\u0436\u0435\u043D Dropbox app key",
  "Dropbox authorization code is required": "\u041D\u0443\u0436\u0435\u043D \u043A\u043E\u0434 \u0430\u0432\u0442\u043E\u0440\u0438\u0437\u0430\u0446\u0438\u0438 Dropbox",
  "Generate a Dropbox auth link before exchanging the code": "\u0421\u043D\u0430\u0447\u0430\u043B\u0430 \u0441\u043E\u0437\u0434\u0430\u0439 \u0441\u0441\u044B\u043B\u043A\u0443 \u0430\u0432\u0442\u043E\u0440\u0438\u0437\u0430\u0446\u0438\u0438 Dropbox, \u043F\u043E\u0442\u043E\u043C \u043E\u0431\u043C\u0435\u043D\u0438\u0432\u0430\u0439 \u043A\u043E\u0434",
  "Dropbox refresh token is missing. Reconnect Dropbox in settings.": "Refresh token Dropbox \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442. \u041F\u043E\u0434\u043A\u043B\u044E\u0447\u0438 Dropbox \u0437\u0430\u043D\u043E\u0432\u043E \u0432 \u043D\u0430\u0441\u0442\u0440\u043E\u0439\u043A\u0430\u0445.",
  "Dropbox returned an empty token response": "Dropbox \u0432\u0435\u0440\u043D\u0443\u043B \u043F\u0443\u0441\u0442\u043E\u0439 \u043E\u0442\u0432\u0435\u0442 \u0442\u043E\u043A\u0435\u043D\u0430",
  "Dropbox did not return an access token": "Dropbox \u043D\u0435 \u0432\u0435\u0440\u043D\u0443\u043B access token",
  "Google OAuth client ID": "Google OAuth client ID",
  "Desktop OAuth client ID from Google Cloud Console": "Desktop OAuth client ID \u0438\u0437 Google Cloud Console",
