function createSecretInput(parent, label, value, placeholder, onChange, password) {
  const field = parent.createDiv({ cls: "umos-sync-secret-field" });
  field.createSpan({ cls: "umos-sync-secret-label", text: label });
  const input = field.createEl("input", {
    cls: "umos-sync-secret-input",
    attr: {
      type: password ? "password" : "text",
      placeholder,
      spellcheck: "false"
    }
  });
  input.value = value;
  input.addEventListener("change", () => void onChange(input.value));
  return input;
}
function createSelect(parent, label, value, options, onChange) {
  const field = parent.createDiv({ cls: "umos-sync-secret-field" });
  field.createSpan({ cls: "umos-sync-secret-label", text: label });
  const select = field.createEl("select", { cls: "umos-sync-secret-input" });
  for (const [optionValue, text] of options) {
    select.createEl("option", { value: optionValue, text });
  }
  select.value = value;
  select.addEventListener("change", () => void onChange(select.value));
}
function createOauthButton(parent, text, cls, onClick) {
  const button = parent.createEl("button", {
    cls: `umos-sync-oauth-button ${cls}`.trim(),
    text,
    attr: { type: "button" }
  });
  button.addEventListener("click", () => void onClick());
  return button;
}
function normalizeMode(value) {
  return value === "pull" || value === "push" ? value : "bidirectional";
}
function normalizeAuthType(value) {
  if (value === "bearer" || value === "oauth")
    return value;
  return "basic";
}
function clampNumber(value, min, max, fallback) {
  const parsed = Number(value);
  if (!Number.isFinite(parsed))
    return fallback;
  return Math.max(min, Math.min(max, Math.round(parsed)));
}
async function copyToClipboard(value) {
  if (!navigator.clipboard)
    throw new Error("Clipboard is unavailable");
  await navigator.clipboard.writeText(value);
}

