var import_obsidian68 = require("obsidian");
var WordOfDayWidget = class extends import_obsidian68.MarkdownRenderChild {
  constructor(containerEl, app, file, fmHelper, property, placeholder) {
    super(containerEl);
    this.currentValue = "";
    this.wordEl = null;
    this.obsidianApp = app;
    this.file = file;
    this.fmHelper = fmHelper;
    this.property = property;
    this.placeholder = placeholder;
  }
  onload() {
    const raw = this.fmHelper.readProperty(this.file, this.property);
    this.currentValue = typeof raw === "string" ? raw : "";
    this.render();
    this.registerEvent(
      this.obsidianApp.metadataCache.on("changed", (changedFile) => {
        if (changedFile.path === this.file.path) {
          const newRaw = this.fmHelper.readProperty(this.file, this.property);
          const newValue = typeof newRaw === "string" ? newRaw : "";
          if (newValue !== this.currentValue) {
            this.currentValue = newValue;
            this.updateDisplay();
          }
        }
      })
    );
  }
  render() {
    this.containerEl.empty();
    const card = createElement("div", {
      cls: "umos-word-of-day",
      parent: this.containerEl
    });
    const header = createElement("div", {
      cls: "umos-word-of-day-header",
      parent: card
    });
    createElement("span", {
      cls: "umos-word-of-day-icon",
      text: "\u{1F4AC}",
      parent: header
    });
    createElement("span", {
      cls: "umos-word-of-day-title",
      text: "Word of the Day",
      parent: header
    });
    this.wordEl = createElement("div", {
      cls: `umos-word-of-day-value ${this.currentValue ? "" : "is-empty"}`,
      text: this.currentValue || this.placeholder,
      parent: card
    });
    this.registerDomEvent(this.wordEl, "click", () => {
      this.startEdit();
    });
  }
  updateDisplay() {
    if (!this.wordEl)
      return;
    this.wordEl.textContent = this.currentValue || this.placeholder;
    this.wordEl.classList.toggle("is-empty", !this.currentValue);
  }
  startEdit() {
    if (!this.wordEl)
      return;
    const input = document.createElement("input");
    input.type = "text";
    input.className = "umos-word-of-day-input";
    input.value = this.currentValue;
    input.placeholder = this.placeholder;
    this.wordEl.textContent = "";
    this.wordEl.appendChild(input);
    this.wordEl.classList.remove("is-empty");
    input.focus();
    const save = () => {
      const newVal = input.value.trim();
      this.currentValue = newVal;
      this.fmHelper.writeProperty(this.file, this.property, newVal || null);
      this.updateDisplay();
    };
    this.registerDomEvent(input, "blur", save);
    this.registerDomEvent(input, "keydown", (e) => {
      if (e.key === "Enter") {
        e.preventDefault();
        input.blur();
      } else if (e.key === "Escape") {
        this.updateDisplay();
      }
    });
  }
};

// src/daily/DailyReviewWidget.ts
var DAILY_PROMPTS = [
  { key: "review_win", label: "What worked?", placeholder: "The best result of the day..." },
  { key: "review_lessons", label: "What should be considered?", placeholder: "Observation, lesson, or adjustment..." },
  { key: "review_tomorrow", label: "Tomorrow focus", placeholder: "One main thing..." }
];
var WEEKLY_PROMPTS = [
  { key: "weekly_review_win", label: "Weekly win", placeholder: "What moved forward most..." },
  { key: "weekly_review_friction", label: "What got in the way?", placeholder: "Recurring friction or noise..." },
  { key: "weekly_review_next", label: "Next week focus", placeholder: "Main direction..." }
];
var DailyReviewWidget = class extends BaseWidget {
  constructor(containerEl, app, file, eventBus, config) {
    super(containerEl);
    this.app = app;
    this.file = file;
    this.config = config;
    this.eventBus = eventBus;
  }
  render() {
    this.containerEl.empty();
    const prompts = this.config.mode === "weekly" ? WEEKLY_PROMPTS : DAILY_PROMPTS;
    const cache = this.app.metadataCache.getFileCache(this.file)?.frontmatter ?? {};
    const root = this.containerEl.createDiv({ cls: "umos-review-widget" });
    const title = this.config.title || (this.config.mode === "weekly" ? "Weekly Review" : "Daily Review");
    root.createEl("h3", { text: title, cls: "umos-review-title" });
    for (const prompt of prompts) {
      const row = root.createDiv({ cls: "umos-review-field" });
      row.createEl("label", { text: prompt.label, cls: "umos-review-label" });
      const input = row.createEl("textarea", {
        cls: "umos-review-input",
        attr: { placeholder: prompt.placeholder }
      });
      input.value = String(cache[prompt.key] ?? "");
      input.addEventListener("change", () => {
        void this.saveField(prompt.key, input.value);
      });
      input.addEventListener("blur", () => {
        void this.saveField(prompt.key, input.value);
      });
    }
  }
  async saveField(property, value) {
    try {
      await this.app.fileManager.processFrontMatter(this.file, (fm) => {
        fm[property] = value;
      });
      this.eventBus.emit("frontmatter:changed", {
        path: this.file.path,
        property,
        value
      });
    } catch (error) {
      console.error("umOS: failed to save review field:", error);
    }
  }
};

