var import_obsidian81 = require("obsidian");
var TextInput = class extends import_obsidian81.MarkdownRenderChild {
  constructor(containerEl, config, file, fmHelper, app) {
    super(containerEl);
    this.inputEl = null;
    this.config = config;
    this.file = file;
    this.fmHelper = fmHelper;
    this.obsidianApp = app;
    this.currentValue = "";
  }
  onload() {
    const raw = this.fmHelper.readProperty(this.file, this.config.property);
    this.currentValue = typeof raw === "string" ? raw : "";
    this.render();
    this.registerEvent(
      this.obsidianApp.metadataCache.on("changed", (changedFile) => {
        if (changedFile.path === this.file.path) {
          const newRaw = this.fmHelper.readProperty(this.file, this.config.property);
          const newValue = typeof newRaw === "string" ? newRaw : "";
          if (newValue !== this.currentValue && document.activeElement !== this.inputEl) {
            this.currentValue = newValue;
            if (this.inputEl) {
              this.inputEl.value = this.currentValue;
            }
          }
        }
      })
    );
  }
  render() {
    this.containerEl.empty();
    const wrapper = createElement("div", {
      cls: "umos-input-wrapper umos-text-wrapper",
      parent: this.containerEl
    });
    createElement("span", {
      cls: "umos-text-label",
      text: this.config.label,
      parent: wrapper
    });
    if (this.config.multiline) {
      const textarea = document.createElement("textarea");
      textarea.className = "umos-text-input umos-text-textarea umos-focusable";
      textarea.placeholder = this.config.placeholder || "";
      textarea.value = this.currentValue;
      textarea.rows = 3;
      textarea.setAttribute("aria-label", this.config.label);
      wrapper.appendChild(textarea);
      this.inputEl = textarea;
      this.registerDomEvent(textarea, "blur", () => {
        this.save(textarea.value);
      });
      this.registerDomEvent(textarea, "keydown", (e) => {
        if (e.key === "Escape") {
          textarea.blur();
        }
      });
    } else {
      const input = document.createElement("input");
      input.type = "text";
      input.className = "umos-text-input umos-focusable";
      input.placeholder = this.config.placeholder || "";
      input.value = this.currentValue;
      input.setAttribute("aria-label", this.config.label);
      wrapper.appendChild(input);
      this.inputEl = input;
      this.registerDomEvent(input, "blur", () => {
        this.save(input.value);
      });
      this.registerDomEvent(input, "keydown", (e) => {
        if (e.key === "Enter") {
          input.blur();
        } else if (e.key === "Escape") {
          input.value = this.currentValue;
          input.blur();
        }
      });
    }
  }
  save(value) {
    if (value !== this.currentValue) {
      this.currentValue = value;
      this.fmHelper.writeProperty(this.file, this.config.property, this.currentValue);
    }
  }
};

// src/input/ProgressInput.ts
var import_obsidian82 = require("obsidian");
var ProgressInput = class extends import_obsidian82.MarkdownRenderChild {
  constructor(containerEl, config, file, fmHelper, app) {
    super(containerEl);
    this.barEl = null;
    this.percentEl = null;
    this.currentDisplayEl = null;
    this.totalDisplayEl = null;
    this.config = config;
    this.file = file;
    this.fmHelper = fmHelper;
    this.obsidianApp = app;
    this.currentValue = 0;
    this.totalValue = 100;
  }
  onload() {
    const rawCurrent = this.fmHelper.readProperty(this.file, this.config.propertyCurrent);
    const rawTotal = this.fmHelper.readProperty(this.file, this.config.propertyTotal);
    this.currentValue = typeof rawCurrent === "number" ? rawCurrent : 0;
    this.totalValue = typeof rawTotal === "number" ? rawTotal : 100;
    this.render();
    this.registerEvent(
      this.obsidianApp.metadataCache.on("changed", (changedFile) => {
        if (changedFile.path === this.file.path) {
          const newCurrent = this.fmHelper.readProperty(this.file, this.config.propertyCurrent);
          const newTotal = this.fmHelper.readProperty(this.file, this.config.propertyTotal);
          const c = typeof newCurrent === "number" ? newCurrent : 0;
          const t2 = typeof newTotal === "number" ? newTotal : 100;
          if (c !== this.currentValue || t2 !== this.totalValue) {
            this.currentValue = c;
            this.totalValue = t2;
            this.updateVisual();
          }
        }
      })
    );
  }
  render() {
    this.containerEl.empty();
    const wrapper = createElement("div", {
      cls: "umos-input-wrapper umos-progress-wrapper",
      parent: this.containerEl
    });
    const header = createElement("div", {
      cls: "umos-progress-header",
      parent: wrapper
    });
    createElement("span", {
      cls: "umos-progress-label",
      text: this.config.label,
      parent: header
    });
    const numbers = createElement("div", {
      cls: "umos-progress-numbers",
      parent: header
    });
    this.currentDisplayEl = createElement("span", {
      cls: `umos-progress-current ${this.config.editable ? "umos-progress-editable" : ""}`,
      text: String(this.currentValue),
      parent: numbers
    });
    createElement("span", {
      cls: "umos-progress-separator",
      text: " / ",
      parent: numbers
    });
    this.totalDisplayEl = createElement("span", {
      cls: `umos-progress-total ${this.config.editable ? "umos-progress-editable" : ""}`,
      text: String(this.totalValue),
      parent: numbers
    });
    this.percentEl = createElement("span", {
      cls: "umos-progress-percent",
      parent: numbers
    });
    const barContainer = createElement("div", {
      cls: "umos-progress-container",
      parent: wrapper
    });
    this.barEl = createElement("div", {
      cls: "umos-progress-bar",
      parent: barContainer
    });
    this.barEl.style.background = this.config.color || "var(--umos-accent)";
    this.updateVisual();
    if (this.config.editable && this.currentDisplayEl && this.totalDisplayEl) {
      this.registerDomEvent(this.currentDisplayEl, "click", () => {
        this.editNumber("current");
      });
      this.registerDomEvent(this.totalDisplayEl, "click", () => {
        this.editNumber("total");
      });
    }
  }
  editNumber(which) {
    const displayEl = which === "current" ? this.currentDisplayEl : this.totalDisplayEl;
    if (!displayEl)
      return;
    const currentVal = which === "current" ? this.currentValue : this.totalValue;
    const input = document.createElement("input");
    input.type = "number";
    input.className = "umos-progress-inline-input";
    input.value = String(currentVal);
    input.min = "0";
    displayEl.textContent = "";
    displayEl.appendChild(input);
    input.focus();
    input.select();
    const save = () => {
      const newVal = parseInt(input.value, 10);
      if (!isNaN(newVal) && newVal >= 0) {
        if (which === "current") {
          this.currentValue = newVal;
          this.fmHelper.writeProperty(this.file, this.config.propertyCurrent, newVal);
        } else {
          this.totalValue = newVal;
          this.fmHelper.writeProperty(this.file, this.config.propertyTotal, newVal);
        }
      }
      this.updateVisual();
    };
    this.registerDomEvent(input, "blur", save);
    this.registerDomEvent(input, "keydown", (e) => {
      if (e.key === "Enter") {
        input.blur();
      } else if (e.key === "Escape") {
        input.value = String(currentVal);
        input.blur();
      }
    });
  }
  updateVisual() {
    const percent = this.totalValue > 0 ? Math.min(100, Math.round(this.currentValue / this.totalValue * 100)) : 0;
    if (this.barEl) {
      this.barEl.style.width = `${percent}%`;
    }
    if (this.percentEl) {
      this.percentEl.textContent = ` (${percent}%)`;
    }
    if (this.currentDisplayEl && !this.currentDisplayEl.querySelector("input")) {
      this.currentDisplayEl.textContent = String(this.currentValue);
    }
    if (this.totalDisplayEl && !this.totalDisplayEl.querySelector("input")) {
      this.totalDisplayEl.textContent = String(this.totalValue);
    }
  }
};

